const t={configTemplates:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Готовые к вставке блоки конфигурации Klipper и макросы — стартовые последовательности, работа с филаментом, input shaping, карта стола и многое другое. Скопируйте один из них и вставьте в свой printer.cfg (Редактор конфигурации — удобное место для вставки)."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Справка"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"О шаблонах конфигурации"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Закрыть"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Как пользоваться"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Отфильтруйте по категории, чтобы найти макрос или блок конфигурации."}},{t:0,b:{t:2,i:[{t:3}],s:"Прочитайте описание и узнайте, какие секции ему нужны."}},{t:0,b:{t:2,i:[{t:3}],s:"Скопируйте шаблон, вставьте его в свою конфигурацию и настройте значения."}}],topics:{what:{title:{t:0,b:{t:2,i:[{t:3}],s:"Что это такое"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Подобранный набор распространённых строительных блоков Klipper: gcode_macro (PRINT_START, PAUSE/RESUME, загрузка/выгрузка филамента, M600) и секции конфигурации ([input_shaper], [bed_mesh], [firmware_retraction], …). Это отправные точки — прочитайте каждый и настройте под свою машину."}}},insert:{title:{t:0,b:{t:2,i:[{t:3}],s:"Вставка шаблона"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Скопируйте шаблон, затем вставьте его в свой printer.cfg — режим Raw в Редакторе конфигурации удобен для этого. После сохранения перезапуск прошивки применит изменения. Всегда сначала проверяйте значения; значения по умолчанию здесь разумны, но не настроены под ваш принтер."}}},sections:{title:{t:0,b:{t:2,i:[{t:3}],s:"Необходимые секции"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Каждый шаблон перечисляет секции конфигурации, которые он определяет или от которых зависит. Если секция уже существует в вашей конфигурации, объедините ключи, а не вставляйте дубликат (дублирующаяся секция отклоняется при запуске)."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Глоссарий"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{template:{term:{t:0,b:{t:2,i:[{t:3}],s:"Шаблон"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Готовый к вставке фрагмент конфигурации Klipper или G-code макроса, который вы копируете в printer.cfg."}}},macro:{term:{t:0,b:{t:2,i:[{t:3}],s:"gcode_macro"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Именованная команда, которую вы определяете в конфигурации (например, PRINT_START) и которая выполняет последовательность G-code."}}},section:{term:{t:0,b:{t:2,i:[{t:3}],s:"Секция"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Блок конфигурации [в квадратных скобках], например [bed_mesh] — единица, в которую группируется конфигурация Klipper."}}}}},category:{label:{t:0,b:{t:2,i:[{t:3}],s:"Категория"}},all:{t:0,b:{t:2,i:[{t:3}],s:"Все категории"}}},template:{copy:{t:0,b:{t:2,i:[{t:3}],s:"Копировать"}},copied:{t:0,b:{t:2,i:[{t:3}],s:"Скопировано!"}},requires:{t:0,b:{t:2,i:[{t:3,v:"Секции: "},{t:4,k:"sections"}]}},requiresNone:{t:0,b:{t:2,i:[{t:3}],s:"—"}}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" шаблонов"}]}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Загрузка шаблонов…"}},error:{t:0,b:{t:2,i:[{t:3}],s:"Не удалось загрузить шаблоны."}},empty:{t:0,b:{t:2,i:[{t:3}],s:"В этой категории нет шаблонов."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Повторить"}}}}};export{t as default};
